import json, os
from pathlib import Path

base = Path(os.path.expanduser("~/.claude/projects/-private-tmp-dirigent-smoke-test"))

# Get all sessions from latest run (after 15:53 = timestamp of last smoke test start)
sessions = []
for f in sorted(base.glob("*.jsonl"), key=lambda p: p.stat().st_mtime, reverse=True):
    mtime = f.stat().st_mtime
    if mtime < 1775135600:  # before 15:53
        break
    first_user = ""
    model_used = ""
    skill_calls = []
    tool_counts = {}
    errors = []
    with open(f) as fh:
        for line in fh:
            msg = json.loads(line)
            role = msg.get("message", {}).get("role", "")
            model = msg.get("message", {}).get("model", "")
            content = msg.get("message", {}).get("content", "")
            if model and not model_used:
                model_used = model
            if role == "user" and isinstance(content, str) and not first_user:
                first_user = content[:100].replace("\n", " ")
            if isinstance(content, list):
                for c in content:
                    if c.get("type") == "tool_use":
                        name = c["name"]
                        tool_counts[name] = tool_counts.get(name, 0) + 1
                        if name == "Skill":
                            skill_calls.append(c.get("input", {}).get("skill", ""))
                    if c.get("type") == "text":
                        txt = c.get("text", "")
                        if "error" in txt.lower() or "failed" in txt.lower():
                            for line in txt.split("\n"):
                                if "error" in line.lower() or "failed" in line.lower():
                                    errors.append(line.strip()[:120])
            # Check tool results for errors
            if isinstance(content, list):
                for c in content:
                    if c.get("type") == "tool_result" and c.get("is_error"):
                        errors.append(f"Tool error: {str(c.get('content',''))[:100]}")

    # Check for subagent transcripts
    subagent_dir = f.parent / f.stem / "subagents"
    subagents = list(subagent_dir.glob("*.jsonl")) if subagent_dir.exists() else []

    sessions.append({
        "file": f.name[:8],
        "prompt": first_user,
        "model": model_used.replace("claude-", "").replace("-20251001", ""),
        "skills": skill_calls,
        "tools": tool_counts,
        "errors": errors[:3],
        "subagents": len(subagents),
    })

print(f"{'Session':<10} {'Model':<15} {'Skills':<30} {'Subagents':<10} {'Tools'}")
print("=" * 120)
for s in sessions:
    skills = ", ".join(s["skills"]) if s["skills"] else "-"
    tools = ", ".join(f"{k}:{v}" for k, v in sorted(s["tools"].items()))
    print(f"{s['file']:<10} {s['model']:<15} {skills:<30} {s['subagents']:<10} {tools}")
    print(f"  prompt: {s['prompt'][:100]}")
    for e in s["errors"]:
        print(f"  ERROR: {e}")
    print()
